export interface APQCProcess {
  id: string;
  name: string;
  l1_id: string;
  l1_name: string;
  type: 'operating' | 'support';
  value_proposition: string;
  work_products: string[];
  tech_stacks: Record<string, string[]>;
  org_model: { type: string; label: string; description: string };
  agents: { name: string; role: 'orchestrator' | 'domain_agent' | 'doer' }[];
  tools: string[];
  ebitda: {
    revenue_impact: number;
    cost_reduction: number;
    efficiency_gain: number;
    risk_mitigation: number;
    est_impact_pct: number;
    timeline: '0-6 mo' | '6-12 mo' | '12-18 mo';
  };
}

