export function getProcessesByL1(l1_id: string): APQCProcess[] {
  return apqcProcesses.filter(p => p.l1_id === l1_id);
}

export function getProcessById(id: string): APQCProcess | undefined {
  return apqcProcesses.find(p => p.id === id);
}
